But, I don't think it's in the function you pasted here. The following code:
```golang
package main

import (
	"encoding/json"
	"os"
)

func PrintGenericJSON(data any) error {
	enc := json.NewEncoder(os.Stdout)
	// by default, json marshallers will force utf=8 from
	// a string.
	enc.SetEscapeHTML(false)
	enc.SetIndent("", "     ")
	return enc.Encode(data)
}

func main() {
	v := map[string]string{"foo": "&&"}
	PrintGenericJSON(v)
}
```
prints:
```shell
go run main.go
{
     "foo": "&&"
}
```
